var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"무척 커다란 전차네요. 메카닉스에 저런 게 있는 줄은 몰랐어요.","JPN":"とても大きな戦車ですね。メカニックスにあんな物があるとは知りませんでした。","ENG":"What a massive tank. I didn’t know Mechanics had such a thing.","TWN":"好大的戰車，沒想到機械裡竟然有那種東西。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"상혁 오라버니가 사들이신 걸까요? 어릴 때부터 커다란 기계를 좋아하셨으니까요.","JPN":"タツヤお兄様が買い付けた物でしょうか？\\n子どもの頃から大きな機械が好きでしたから。","ENG":"Did Sanghyuk buy this? He was also a fan of gigantic machinery since he was little.","TWN":"是沈尚哥買的嗎？他從小就很喜歡大型的機械。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야! 그렇게 여유 부릴 때가 아니다!","JPN":"ユイちゃん！　そんな余裕を見せてる時間はないわ！","ENG":"Jia! Stop fooling around!","TWN":"小佳！現在不是討論這個問題的時候啦！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아까부터 우리 쪽 공격은 하나도 안 통하지 않느냐!","JPN":"さっきからこっちの攻撃が全然効いてないじゃない！","ENG":"Our attacks aren’t even making a dent in that thing!","TWN":"我們這邊的攻擊對他們來說根本就沒用嘛！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 그래서 이제 막 준비를 마친 참이에요.","JPN":"はい。ちょうど今、準備が整いました。","ENG":"Yes, I’m almost finished getting ready.","TWN":"對，所以我才剛準備好而已。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"응? 준비라니?","JPN":"うん？　準備って？","ENG":"Hmm? Getting ready?","TWN":"嗯？準備什麼？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"구동계의 취약점을 파악하려면 시간이 필요했거든요.","JPN":"駆動システムの弱点の把握に時間がかかりました。","ENG":"I needed time to find the drivetrain’s weak point.","TWN":"掌握驅動器的弱點需要一些時間，"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"꼭 부술 필요 없이 움직이지 못하게만 만들어도 충분하니까요.","JPN":"別に壊さなくても、動けないようにするだけで十分でしょう。","ENG":"It’s good enough to simply immobilize it without breaking it.","TWN":"我不打算毀掉整台機械，只要讓它不能運作就好。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"대, 대단하구나! 분신들만으로 저 커다란 쇳덩이를 꼼짝 못하게 만들다니!","JPN":"す、すごいじゃない！　分身だけであのデカい鉄の塊を無力化するなんて！","ENG":"A-amazing! You stopped that chunk of metal with only your clones!","TWN":"好…好厲害！竟然光靠分身，就能夠讓那個巨大的鐵塊動彈不得！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"자, 이 틈에 어서 빠져 나가요.","JPN":"さあ、この隙に早く逃げましょう。","ENG":"We need to leave now.","TWN":"我們趁現在逃走吧！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"그냥 가시게 내버려 둘 수 없습니다, 아가씨!","JPN":"そうはいきません、お嬢様！","ENG":"I can’t let you leave, Miss!","TWN":"小姐！恕我無法放行！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"아가씨가 사람을 해칠 분이라고는 생각하지 않습니다.","JPN":"お嬢様が人を傷つけるような方だとは思いません。","ENG":"I know you aren’t the kind of person who harms others.","TWN":"我不認為小姐是殺人兇手。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"하지만 정말 결백하시다면 도망치실 필요도 없는 것 아닙니까?","JPN":"ですが、本当に潔白ならば、逃げる必要もないのではありませんか？","ENG":"But, if you truly were innocent, you wouldn’t have to run away!","TWN":"但若小姐真是清白的，又何須要逃呢？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"도망만 친다고 문제가 해결되진 않습니다. 이대로는 의심만 더 키울 뿐이에요.","JPN":"逃げることで問題が解決できるわけではありません。\\nこのままでは疑惑が増すだけです。","ENG":"Running away doesn’t solve anything. It only makes things worse.","TWN":"逃跑並不能解決問題，只會令人更加起疑而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……죄송해요.","JPN":"……ごめんなさい。","ENG":"...I'm sorry.","TWN":"……抱歉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 할아버님께서 가르쳐 주셨어요. 자신을 믿는 사람들을 외면해서는 안 된다고요.","JPN":"しかし、お祖父様に教わりました。\\n自分を信じてくれる人々から目を逸らしてはいけないと。","ENG":"But Grandfather taught me to never turn away from people who believe in me.","TWN":"不過我爺爺有說，不能對相信自己的人視而不見。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"멤버들이 진실을 밝혀 달라고 부탁했는데, 여기서 멈출 수는 없어요.","JPN":"メンバーの皆さんに、真実を明かしてほしいと頼まれたのに、\\nここでやめるわけにはいきません。","ENG":"I can’t stop now, when my members have trusted me to reveal the truth.","TWN":"大家都希望我可以查清真相，所以我不能就此打住。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"그렇게까지 말씀하신다면 저 역시…….","JPN":"そこまでおっしゃるなら私も……","ENG":"If that is your answer...","TWN":"就算是這樣，我也……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GOLIATH_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ff3636>충전 완료. 적을 분쇄한다.</color>","JPN":"<color=#ff3636>チャージ完了。敵を粉砕する。</color>","ENG":"<color=#ff3636>Charge complete. Crush the enemy.</color>","TWN":"<color=#ff3636>填彈完畢，粉碎敵人。</color>"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLIATH_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_07"},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"위험해요!! 다들 엎드리세요!","JPN":"危ない！！　みんな伏せてください！","ENG":"Watch out! Everyone, duck!","TWN":"危險！！全部趴下！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"내, 내가…… 어떻게 살아 있는 거지?","JPN":"わ、私……生きてる？","ENG":"H-how am... I still alive?","TWN":"我……竟然還活著？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"구동계가 아니라 동력로까지 끊었어야 했네요.","JPN":"駆動システムだけではなく、動力まで切っておくべきでしたね。","ENG":"Looks like I should’ve cut the power line, not the drivetrain.","TWN":"我剛剛應該連動力爐一起破壞掉才對！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하마터면 위험할 뻔했어요. 모두 다치지 않으셨나요?","JPN":"本当に危ないところでした。皆さん、お怪我はありませんか？","ENG":"That was a close call. Is everyone all right?","TWN":"真是好險！大家都沒受傷吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ffd34c>하마터면</color>이 아니잖니?! 공장 절반이 날아갔잖아!","JPN":"<color=#ffd34c>危ないところ</color>じゃないわよ！？　工場の半分が吹き飛んだわ！","ENG":"<color=#ffd34c>A close call</color>?! Half of the factory’s destroyed!","TWN":"<color=#ffd34c>好險</color>什麼？！一半的工廠都毀咧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"아가씨……. 왜 저를…….","JPN":"お嬢様……なぜ私を……","ENG":"Miss Jia... W-why did you...?","TWN":"小姐……為什麼要救我……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님은 직원의 일도 자기 일처럼 생각하라고 하셨거든요.","JPN":"お祖父様は、社員のことは自分の事のように考えなさいとおっしゃいました。","ENG":"Grandfather said to treat employees how I would want them to treat me.","TWN":"我爺爺有說，要把員工的事當成自己的事。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 다치기 싫은 것처럼, 대장님도 다치기 싫으셨을 거예요.","JPN":"私が怪我をしたくないように、隊長も怪我をしたくないはずだと思っただけです。","ENG":"Much like I dislike getting hurt, I bet you wouldn’t like it as well.","TWN":"我不想受傷的話，那你應該也不想受傷吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"……그렇게 된 겁니다.","JPN":"……説明は以上です。","ENG":"So, that's what happened.","TWN":"……事情的經過就是這樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그랬군요. 아가씨가…….","JPN":"なるほど。お嬢様が……","ENG":"I see...","TWN":"原來是這樣，小姐她……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"단 한 번뿐이지만, 여기로 발령받기 전에 아가씨를 뵀던 적이 있습니다.","JPN":"一度だけですが、ここに配属される前にお嬢様にお会いしたことがあります。","ENG":"Before I was assigned to work here, I remember seeing Miss Jia.","TWN":"雖然只有一次，但我在被分發到這裡來之前，有見過小姐一次。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"본사 바깥에서 경호를 서던 저희들을 위해 손난로를 나눠 주실 만큼 따뜻한 분이셨죠.","JPN":"本社の外で警護の仕事をしていた我々のために、\\nカイロを配ってくれるほど心優しい方でした。","ENG":"She was a kind, young lady who handed out hand warmers to the guards stationed outside the headquarters.","TWN":"當時我們在總公司外面站崗，小姐就拿暖暖包給我們，她是一個非常溫暖的人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"그 때나 지금이나…… 살인 같은 짓을 저지를 분이 아니셨어요.","JPN":"あの時も今も……殺人なんてするような方ではありません。","ENG":"Even then, and even now... I know deep down that she's not the type of person who would commit murder.","TWN":"無論是當時或是現在……她都不會是一個會犯下殺人案的人！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"대, 대장님! 큰일입니다! 잠시 와 주셔야겠습니다!","JPN":"た、隊長！　大変です！　ちょっと来てください！","ENG":"S-sir! I think you should come and see this!","TWN":"隊…隊長！大事不好啦！要請您來一趟！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"음……?","JPN":"うん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"왜 그렇게 허둥거려? 대체 뭘 봤길래?","JPN":"何をそんなに慌ててるんだ？　何を見たの？","ENG":"What’s wrong? Why’re you acting like that?","TWN":"怎麼嚇成這樣？你到底是看到什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이 사람은…… 신상혁 메카닉스 대표……?","JPN":"この方は……ヒメノ・タカシメカニックス代表……？","ENG":"That’s... Mechanics CEO... Shin Sanghyuk...?","TWN":"這個人……是機械的代表 沈尚……？"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"……끔찍해.","JPN":"……ひどい。","ENG":"Just horrific...","TWN":"……好嚇人！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"어째서 이제야 알려 준 거야! 대표 같은 고위직부터 경호하는 게 우선 아니야?!","JPN":"なんで今ごろ気づいたんだよ！\\n代表みたいなお偉いさんを警護するのが最優先でしょ！？","ENG":"What took you so long to tell me?! Isn't it first and foremost to protect high-ranking officials such as the CEO?!","TWN":"為何現在才通報！保護代表不是你們的最重要的任務嗎？！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"죄송합니다! 대표님께선 작업실에 계실 때 방해 받는 걸 워낙 싫어하셔서……!","JPN":"申し訳ございません！　代表は作業室にいらっしゃる時に邪魔されるのをひどく嫌っていまして……","ENG":"My apologies! Mr. Shin hates being interrupted in his private studio...!","TWN":"很抱歉！這是因為代表在工作室時，不喜歡有人打擾……！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"상황이 잠잠해진 뒤에 보고드리려고 찾아왔는데, 그 때는 이미…….","JPN":"状況が収まった後に報告しようと部屋に伺ったら、すでに……","ENG":"I came here to report once things had calmed down, but by then...","TWN":"原本想說觀察一下狀況再跟隊長報告，沒想到已經……"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"역시……!","JPN":"やっぱり……！","ENG":"I knew it!","TWN":"我就知道……！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"내 안에서 속삭이는 <color=#ffd34c>파사의 목소리</color>가 옳았어!","JPN":"私の中で囁いている<color=#ffd34c>破邪の声</color>は正しかった！","ENG":"The <color=#ffd34c>Voice of Evil Eradication</color> was right!","TWN":"<color=#ffd34c>破邪之聲</color>告訴我的是對的！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"남들 앞에선 위선 떨다가 뒤로는 이런 흉악무도한 짓을 저지르다니……!","JPN":"人前では偽善者ぶって、裏ではこんな凶悪非道なことをするなんて……！","ENG":"How dare you act hypocritically in front of others and then commit such atrocities...!","TWN":"人前裝得一副大好人的樣子，人後卻做出這種傷天害理的事……！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"반드시 타도하고 말겠어, 신지아 대표! 파사의 추격자로서!","JPN":"破邪の追跡者として、絶対に倒してやる！　ヒメノ・ユイ代表！","ENG":"As the Chaser of Evil, I will arrest you myself!","TWN":"我以破邪追擊者的名義發誓！沈佳代表，我一定會逮到你！"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};